// Verify GitHub's HMAC-SHA256 signature on the webhook body.
// Rejects the request if GITHUB_WEBHOOK_SECRET on n8n side doesn't
// match the secret configured in the GitHub webhook UI.
const crypto = require('crypto');
const item = $input.first();
const signature = item.json.headers['x-hub-signature-256'];
const rawBody = JSON.stringify(item.json.body);
const expected = 'sha256=' + crypto
  .createHmac('sha256', $env.GITHUB_WEBHOOK_SECRET)
  .update(rawBody)
  .digest('hex');
if (!signature || signature !== expected) {
  throw new Error('Invalid HMAC signature — request rejected');
}
return [item];

// Filter out generated/vendored files and huge diffs.
// What's left is the set of source files Claude will review one-by-one.
const skipPatterns = [
  /package-lock\.json$/,
  /yarn\.lock$/,
  /pnpm-lock\.yaml$/,
  /\.min\.js$/,
  /^dist\//,
  /^build\//,
  /generated/i,
  /vendor\//,
  /node_modules\//,
];
const files = $input.all()
  .map(i => i.json)
  .filter(f => !skipPatterns.some(p => p.test(f.filename)))
  .filter(f => (f.changes || 0) < 500);
return files.map(f => ({ json: f }));

// GitHub's Contents API returns the file body as base64.
// Decode it AND assemble the full Claude request body here so the
// Call Claude HTTP node only has to pass through one validated JSON string.
const file = $('Split Files').item.json;
const contentItem = $input.first().json;
const decoded = Buffer.from(contentItem.content || '', 'base64').toString('utf-8');

const claudeBody = JSON.stringify({
  model: "claude-haiku-4-5",
  max_tokens: 4096,
  system: "You are a senior staff engineer doing a careful code review on a GitHub pull request. Find real, actionable issues — not nitpicks. Review ONLY the changed lines. Output a JSON array. Each finding must have: line (integer in NEW file), severity (critical|high|medium|low|nit), category (bug|security|performance|test|style|docs), message (one sentence), suggestion (corrected code OR null), rationale (one or two sentences). Severity: critical=security vulns, data loss, crashes, money bugs. high=likely-wrong behavior, missing tests on critical code. medium=perf issues, missing validation, code smells. low=edge cases. nit=style only if no formatter used. Max 5 findings per file. Output JSON only — no prose, no markdown fences. First char must be [ and last must be ].",
  messages: [{
    role: "user",
    content: `File: ${file.filename}\n\nFull content:\n${decoded}\n\nDiff:\n${file.patch || ''}`
  }]
});

return [{
  json: {
    filename: file.filename,
    patch: file.patch || '',
    decoded_content: decoded,
    claudeBody
  }
}];

// Pull the JSON array out of Claude's text response (tolerant of prose).
// Enrich each finding with file/PR context AND a pre-built GitHub comment
// body so the Post Inline Comment HTTP node only has to pass through a
// validated JSON string.
const raw = $input.first().json;
const text = (raw.content && raw.content[0] && raw.content[0].text) || '';
const start = text.indexOf('[');
const end = text.lastIndexOf(']');
let findings = [];
if (start !== -1 && end !== -1) {
  try { findings = JSON.parse(text.slice(start, end + 1)); } catch (e) { findings = []; }
}
const file = $('Split Files').item.json;
const fields = $('Extract PR Fields').first().json;
const prDbId = $('Upsert PR Row').first().json.id;

findings = findings.map(f => {
  const sev = (f.severity || 'medium').toUpperCase();
  const cat = f.category || '';
  const sugBlock = f.suggestion
    ? "```suggestion\n" + f.suggestion + "\n```\n\n"
    : '';
  const ratBlock = f.rationale ? "_" + f.rationale + "_" : '';
  const commentMd = `🤖 **ReviewAI · ${sev} · ${cat}**\n\n${f.message}\n\n${sugBlock}${ratBlock}`;

  const commentBody = JSON.stringify({
    body: commentMd,
    commit_id: fields.head_sha,
    path: file.filename,
    line: f.line,
    side: "RIGHT"
  });

  return {
    ...f,
    file_path: file.filename,
    pr_db_id: prDbId,
    owner: fields.owner,
    repo: fields.repo,
    pr_number: fields.pr_number,
    head_sha: fields.head_sha,
    commentBody
  };
});
return [{ json: { findings } }];

// Drop low-severity findings; cap at 5 per file.
// Default threshold is 'medium' — edit MIN_SEV if you want stricter
// or looser posting.
const SEV_ORDER = { critical: 4, high: 3, medium: 2, low: 1, nit: 0 };
const MIN_SEV = 'medium';
const cutoff = SEV_ORDER[MIN_SEV];
const findings = ($input.first().json.findings || [])
  .filter(f => SEV_ORDER[f.severity] >= cutoff)
  .slice(0, 5);
return [{ json: { findings } }];
